# setup-pwa-gestao-projetos.ps1
# Cria PWA instalavel para o app Alexandre Dias | Interiores - Gestao de Projetos
# Marcador: GESTAO_PROJETOS_PWA_V2

$ErrorActionPreference = "Stop"

Write-Host "Criando estrutura PWA..." -ForegroundColor Cyan

New-Item -ItemType Directory -Force -Path ".\public\icons" | Out-Null

$icon192 = @"

"@

$icon512 = @"

"@

$favicon = @"

"@

[System.Convert]::FromBase64String($icon192) | Set-Content -Path ".\public\icons\icon-192.png" -Encoding Byte
[System.Convert]::FromBase64String($icon512) | Set-Content -Path ".\public\icons\icon-512.png" -Encoding Byte
[System.Convert]::FromBase64String($favicon) | Set-Content -Path ".\public\favicon.png" -Encoding Byte

@'
{
  "id": "/",
  "name": "Alexandre Dias | Gestão de Projetos",
  "short_name": "Gestão Projetos",
  "description": "Sistema premium para gestão de projetos de interiores, clientes, prazos e financeiro.",
  "start_url": "/",
  "scope": "/",
  "display": "standalone",
  "display_override": ["window-controls-overlay", "standalone", "browser"],
  "orientation": "portrait-primary",
  "background_color": "#f6efe4",
  "theme_color": "#2d1d17",
  "categories": ["productivity", "business"],
  "lang": "pt-BR",
  "icons": [
    {
      "src": "/icons/icon-192.png",
      "sizes": "192x192",
      "type": "image/png",
      "purpose": "any"
    },
    {
      "src": "/icons/icon-192.png",
      "sizes": "192x192",
      "type": "image/png",
      "purpose": "maskable"
    },
    {
      "src": "/icons/icon-512.png",
      "sizes": "512x512",
      "type": "image/png",
      "purpose": "any"
    },
    {
      "src": "/icons/icon-512.png",
      "sizes": "512x512",
      "type": "image/png",
      "purpose": "maskable"
    }
  ]
}
'@ | Set-Content -Path ".\public\manifest.webmanifest" -Encoding UTF8

@'
// GESTAO_PROJETOS_PWA_V2
const CACHE_NAME = "gestao-projetos-pwa-v2";
const APP_SHELL = [
  "/",
  "/manifest.webmanifest",
  "/icons/icon-192.png",
  "/icons/icon-512.png",
  "/favicon.png"
];

self.addEventListener("install", (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(APP_SHELL)).then(() => self.skipWaiting())
  );
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches.keys().then((keys) =>
      Promise.all(keys.filter((key) => key !== CACHE_NAME).map((key) => caches.delete(key)))
    ).then(() => self.clients.claim())
  );
});

self.addEventListener("fetch", (event) => {
  if (event.request.method !== "GET") return;

  const url = new URL(event.request.url);

  if (url.origin !== self.location.origin) return;

  event.respondWith(
    fetch(event.request)
      .then((response) => {
        const copy = response.clone();
        caches.open(CACHE_NAME).then((cache) => cache.put(event.request, copy));
        return response;
      })
      .catch(() => caches.match(event.request).then((cached) => cached || caches.match("/")))
  );
});
'@ | Set-Content -Path ".\public\sw.js" -Encoding UTF8

@'
// GESTAO_PROJETOS_PWA_V2
if ("serviceWorker" in navigator) {
  window.addEventListener("load", () => {
    navigator.serviceWorker
      .register("/sw.js")
      .catch((error) => console.warn("Service Worker não registrado:", error));
  });
}
'@ | Set-Content -Path ".\src\pwa-register.js" -Encoding UTF8

$indexPath = ".\index.html"
$index = Get-Content $indexPath -Raw

# Remove favicon antigo do Vite, se existir
$index = $index -replace '<link rel="icon" type="image/svg\+xml" href="/vite\.svg" />\s*', ''
$index = $index -replace '<link rel="icon"[^>]*>\s*', ''

if ($index -notmatch "GESTAO_PROJETOS_PWA_V2") {
  $headTags = @'
    <!-- GESTAO_PROJETOS_PWA_V2 -->
    <link rel="manifest" href="/manifest.webmanifest" />
    <link rel="icon" type="image/png" href="/favicon.png" />
    <link rel="apple-touch-icon" href="/icons/icon-192.png" />
    <meta name="theme-color" content="#2d1d17" />
    <meta name="mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-title" content="Gestão Projetos" />
    <meta name="application-name" content="Gestão Projetos" />

'@
  $index = $index -replace "<head>", "<head>`n$headTags"
}

if ($index -notmatch "/src/pwa-register.js") {
  $index = $index -replace "</body>", '    <script type="module" src="/src/pwa-register.js"></script>' + "`n  </body>"
}

Set-Content -Path $indexPath -Value $index -Encoding UTF8

Write-Host ""
Write-Host "PWA criado com sucesso." -ForegroundColor Green
Write-Host "Arquivos criados/alterados:" -ForegroundColor Green
Write-Host "- public/manifest.webmanifest"
Write-Host "- public/sw.js"
Write-Host "- public/favicon.png"
Write-Host "- public/icons/icon-192.png"
Write-Host "- public/icons/icon-512.png"
Write-Host "- src/pwa-register.js"
Write-Host "- index.html"
Write-Host ""
Write-Host "Agora rode: npm run dev" -ForegroundColor Cyan
